const (
	maxProtoSize     = 64 * 1024 // 64KB max proto definition size
	maxMessageCount  = 50
	maxFieldCount    = 100
	maxNestingDepth  = 5
	compilationTimeout = 10 * time.Second
)

// validateProtoContent performs strict validation on the proto content
// to prevent injection attacks and malicious definitions.
func validateProtoContent(protoContent string) error {
	if len(protoContent) == 0 {
		return errors.New("proto content is empty")
	}
	if len(protoContent) > maxProtoSize {
		return fmt.Errorf("proto content exceeds maximum size of %d bytes", maxProtoSize)
	}

	// Check for null bytes (could be used for injection)
	if strings.ContainsRune(protoContent, 0) {
		return errors.New("proto content contains null bytes")
	}

	// Only allow printable ASCII and common whitespace
	for i, r := range protoContent {
		if r > unicode.MaxASCII {
			return fmt.Errorf("non-ASCII character at position %d", i)
		}
		if !unicode.IsPrint(r) && r != '\n' && r != '\r' && r != '\t' {
			return fmt.Errorf("non-printable character at position %d", i)
		}
	}

	// Disallow import statements to prevent file inclusion attacks
	importPattern := regexp.MustCompile(`(?m)^\s*import\s+`)
	if importPattern.MatchString(protoContent) {
		return errors.New("import statements are not allowed in dynamic proto definitions")
	}

	// Disallow options that could affect code generation in dangerous ways
	dangerousOptions := regexp.MustCompile(`(?i)(java_package|go_package|csharp_namespace|php_namespace|ruby_package|objc_class_prefix|swift_prefix|java_outer_classname|java_multiple_files|optimize_for)`)
	if dangerousOptions.MatchString(protoContent) {
		return errors.New("language-specific options are not allowed")
	}

	// Must contain syntax declaration
	syntaxPattern := regexp.MustCompile(`(?m)^\s*syntax\s*=\s*"proto3"\s*;`)
	if !syntaxPattern.MatchString(protoContent) {
		return errors.New("proto definition must use syntax = \"proto3\"")
	}

	// Must contain a package declaration (alphanumeric and dots only)
	packagePattern := regexp.MustCompile(`(?m)^\s*package\s+([a-zA-Z][a-zA-Z0-9_.]*)\s*;`)
	if !packagePattern.MatchString(protoContent) {
		return errors.New("proto definition must contain a valid package declaration")
	}

	// Count messages to prevent resource exhaustion
	messagePattern := regexp.MustCompile(`(?m)\bmessage\s+`)
	if len(messagePattern.FindAllString(protoContent, -1)) > maxMessageCount {
		return fmt.Errorf("too many message definitions (max %d)", maxMessageCount)
	}

	// Check nesting depth by counting brace depth
	maxDepth := 0
	currentDepth := 0
	for _, ch := range protoContent {
		if ch == '{' {
			currentDepth++
			if currentDepth > maxDepth {
				maxDepth = currentDepth
			}
		} else if ch == '}' {
			currentDepth--
		}
	}
	if currentDepth != 0 {
		return errors.New("unbalanced braces in proto definition")
	}
	if maxDepth > maxNestingDepth {
		return fmt.Errorf("nesting depth %d exceeds maximum of %d", maxDepth, maxNestingDepth)
	}

	// Disallow service definitions (we only want message types)
	servicePattern := regexp.MustCompile(`(?m)\bservice\s+`)
	if servicePattern.MatchString(protoContent) {
		return errors.New("service definitions are not allowed in dynamic proto definitions")
	}

	// Disallow any shell metacharacters that could be dangerous
	shellMeta := regexp.MustCompile("[`$|;&<>()!]")
	if shellMeta.MatchString(protoContent) {
		return errors.New("proto content contains disallowed characters")
	}

	return nil
}

// validateProtoName ensures the proto name is safe for use as a filename
func validateProtoName(name string) error {
	if len(name) == 0 || len(name) > 64 {
		return errors.New("proto name must be between 1 and 64 characters")
	}
	// Only allow alphanumeric, underscore, hyphen
	safePattern := regexp.MustCompile(`^[a-zA-Z][a-zA-Z0-9_-]*$`)
	if !safePattern.MatchString(name) {
		return errors.New("proto name must start with a letter and contain only alphanumeric characters, underscores, or hyphens")
	}
	return nil
}

func generateSecureID() (string, error) {
	bytes := make([]byte, 16)
	if _, err := rand.Read(bytes); err != nil {
		return "", err
	}
	return hex.EncodeToString(bytes), nil
}

